/**
 * knowledge-lenses — Lens blueprint system for the knowledge renderer.
 *
 * Each lens is a transparent, editable "recipe" with tunable parameters
 * that control how content is synthesized. Presets are built-in; dynamic
 * lenses are generated by the intelligence engine from user behavior.
 */

/* ── Blueprint Parameter Types ── */

export type LensTone = "neutral" | "vivid" | "technical" | "conversational" | "poetic";
export type LensDepth = "overview" | "standard" | "deep" | "exhaustive";
export type LensAudience = "beginner" | "curious" | "informed" | "expert";
export type LensStructure = "sections" | "narrative" | "qa" | "timeline" | "comparison";
export type LensCitationDensity = "minimal" | "moderate" | "thorough";

export interface LensParams {
  tone: LensTone;
  depth: LensDepth;
  audience: LensAudience;
  structure: LensStructure;
  citationDensity: LensCitationDensity;
  focusAreas: string[];
  excludeAreas: string[];
}

export interface RecommendedSource {
  domain: string;
  reason: string;
  qualityScore: number;
  enabled: boolean;
}

export interface LensBlueprint {
  id: string;
  label: string;
  icon: "BookOpen" | "Newspaper" | "Baby" | "GraduationCap" | "BookText" | "Sparkles" | "User" | "Calculator";
  description: string;
  isPreset: boolean;
  /** Human-readable reason for AI-generated lenses */
  generatedReason?: string;
  /** The tunable recipe */
  params: LensParams;
  /** High-signal sources recommended for this lens */
  recommendedSources?: RecommendedSource[];
}

/* ── Legacy compat type ── */
export interface KnowledgeLens {
  id: string;
  label: string;
  icon: "BookOpen" | "Newspaper" | "Baby" | "GraduationCap" | "BookText" | "Calculator";
  description: string;
}

