/** Legacy flat array for backward compat */
export const KNOWLEDGE_LENSES: KnowledgeLens[] = PRESET_BLUEPRINTS.map(b => ({
  id: b.id,
  label: b.label,
  icon: b.icon as KnowledgeLens["icon"],
  description: b.description,
}));

export const DEFAULT_LENS = "encyclopedia";

export function getLens(id: string): KnowledgeLens {
  return KNOWLEDGE_LENSES.find((l) => l.id === id) ?? KNOWLEDGE_LENSES[0];
}

export function getBlueprint(id: string): LensBlueprint {
  return PRESET_BLUEPRINTS.find((b) => b.id === id) ?? PRESET_BLUEPRINTS[0];
}

/** Create a deep copy of a blueprint for editing */
export function cloneBlueprint(bp: LensBlueprint): LensBlueprint {
  return JSON.parse(JSON.stringify(bp));
}

/* ── User-saved custom lenses (localStorage) ── */

const CUSTOM_LENSES_KEY = "uor:custom-lenses";

export function loadCustomLenses(): LensBlueprint[] {
  try {
    const raw = localStorage.getItem(CUSTOM_LENSES_KEY);
    if (!raw) return [];
    return JSON.parse(raw);
  } catch {
    return [];
  }
}

export function saveCustomLens(bp: LensBlueprint): void {
  const existing = loadCustomLenses();
  const idx = existing.findIndex(l => l.id === bp.id);
  if (idx >= 0) existing[idx] = bp;
  else existing.push(bp);
  localStorage.setItem(CUSTOM_LENSES_KEY, JSON.stringify(existing));
}

export function deleteCustomLens(id: string): void {
  const existing = loadCustomLenses().filter(l => l.id !== id);
  localStorage.setItem(CUSTOM_LENSES_KEY, JSON.stringify(existing));
}

